SELECT region_name, coordinates, description
FROM brain_regions
WHERE region_id = 1;

SELECT AVG(m_constrained) AS avg_constrained_connectivity
FROM connectivity_metrics
WHERE region_id = 1;

SELECT COUNT(task_id) AS number_of_tasks
FROM cognitive_tasks
WHERE region_id = 1;

SELECT region_name, coordinates, description, hemisphere
FROM brain_regions
ORDER BY region_name ASC;
